public function getFilesInfo(string $templatesPath): array
{
    $filesInfo = [];
    $filesFound = $this->findFiles($templatesPath);
    foreach ($filesFound as $file) {
        $filesInfo[] = $this->validate($this->getTemplateContents($file), $file);
    }

    return $filesInfo;
}

private function evaluateRuleExpression(string $expression)
{
    $variables = array_merge($this->variables, $this->globals);

    // Set default values for missing InnoDB variables when InnoDB is disabled
    if (! isset($variables['innodb_buffer_pool_size'])) {
        $variables['innodb_buffer_pool_size'] = 0;
    }

    if (! isset($variables['innodb_log_file_size'])) {
        $variables['innodb_log_file_size'] = 0;
    }

    if (! isset($variables['innodb_log_files_in_group'])) {
        $variables['innodb_log_files_in_group'] = 0;
    }

    return $this->expression->evaluate($expression, $variables);
}

public static function checkTokenRequestParam(): void
{
    global $token_mismatch, $token_provided;

    $token_mismatch = true;
    $token_provided = false;

    if (($_SERVER['REQUEST_METHOD'] ?? 'GET') !== 'POST') {
        return;
    }

    if (isset($_POST['token']) && is_scalar($_POST['token']) && strlen((string) $_POST['token']) > 0) {
        $token_provided = true;
        $token_mismatch = ! @hash_equals($_SESSION[' PMA_token '], (string) $_POST['token']);
    }

    if (! $token_mismatch) {
        return;
    }

    // Warn in case the mismatch is result of failed setting of session cookie
    if (isset($_POST['set_session']) && $_POST['set_session'] !== session_id()) {
        trigger_error(
            __(
                'Failed to set session cookie. Maybe you are using HTTP instead of HTTPS to access phpMyAdmin.'
            ),
            PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING
        );
    }

    /**
     * We don't allow any POST operation parameters if the token is mismatched
     * or is not provided.
     */
    $allowList = ['ajax_request'];
    Sanitize::removeRequestVars($allowList);
}

public function checkErrors(): void
{
    if (! $this->errorConfigFile) {
        return;
    }

    $error = '[strong]' . __('Failed to read configuration file!') . '[/strong]'
        . '[br][br]'
        . __('This usually means there is a syntax error in it, please check any errors shown below.')
        . '[br][br]'
        . '[conferr]';
    trigger_error($error, PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING);
}

public function checkServers(): void
{
    // Do we have some server?
    if (! isset($this->settings['Servers']) || count($this->settings['Servers']) === 0) {
        // No server => create one with defaults
        $this->settings['Servers'] = [1 => $this->defaultServer];

        return;
    }

    // We have server(s) => apply default configuration
    $new_servers = [];

    foreach ($this->settings['Servers'] as $server_index => $each_server) {
        // Detect wrong configuration
        if (! is_int($server_index) || $server_index < 1) {
            trigger_error(
                sprintf(__('Invalid server index: %s'), $server_index),
                PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING
            );
        }

        $each_server = array_merge($this->defaultServer, $each_server);

        // Final solution to bug #582890
        // If we are using a socket connection
        // and there is nothing in the verbose server name
        // or the host field, then generate a name for the server
        // in the form of "Server 2", localized of course!
        if (empty($each_server['host']) && empty($each_server['verbose'])) {
            $each_server['verbose'] = sprintf(__('Server %d'), $server_index);
        }

        $new_servers[$server_index] = $each_server;
    }

    $this->settings['Servers'] = $new_servers;
}

public function checkGd2(): void
{
    if ($this->get('GD2Available') === 'yes') {
        $this->set('PMA_IS_GD2', 1);
    } elseif ($this->get('GD2Available') === 'no') {
        $this->set('PMA_IS_GD2', 0);
    } else {
        $this->set('PMA_IS_GD2', (get_defined_constants()['GD_MAJOR_VERSION'] ?? 0) >= 2 ? 1 : 0);
    }
}

public function getOptionValueList($optionPath)
{
    $value = $this->configFile->getDbEntry($optionPath);
    if ($value === null) {
        trigger_error(
            $optionPath . ' - select options not defined',
            PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING
        );

        return [];
    }

    if (! is_array($value)) {
        trigger_error(
            $optionPath . ' - not a static value list',
            PHP_VERSION_ID < 80400 ? E_USER_ERROR : E_USER_WARNING
        );

        return [];
    }

    // convert array('#', 'a', 'b') to array('a', 'b')
    if (isset($value[0]) && $value[0] === '#') {
        // remove first element ('#')
        array_shift($value);

        // $value has keys and value names, return it
        return $value;
    }

    // convert value list array('a', 'b') to array('a' => 'a', 'b' => 'b')
    $hasStringKeys = false;
    $keys = [];
    for ($i = 0, $nb = count($value); $i < $nb; $i++) {
        if (! isset($value[$i])) {
            $hasStringKeys = true;
            break;
        }

        $keys[] = is_bool($value[$i]) ? (int) $value[$i] : $value[$i];
    }

    if (! $hasStringKeys) {
        /** @var array $value */
        $value = array_combine($keys, $value);
    }

    // $value has keys and value names, return it
    return $value;
}
